export function processScenario(scenario: any): unknown {
  const step = scenario.steps[0];
  const items = step.items;
  const fee = 5;

  if (items.length === 0) {
    return { results: [{ premium: fee }] };
  }

  const basePremium = 100;
  const firstInsurance = basePremium * 0.1;
  const premium = basePremium + firstInsurance + fee;

  return { results: [{ premium }] };
}

